use aiken/collection/list
use aiken/interval
use cardano/transaction.{InlineDatum, Output, OutputReference, Transaction}

pub type EscrowDatum {
  beneficiary: ByteArray,
  deadline: Int,
  refund_to: ByteArray,
}

fn find_continuing_output(outputs: List<Output>, own_address: cardano/address.Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == own_address })
}

validator escrow_timeout {
  spend(
    datum: Option<EscrowDatum>,
    _redeemer: Data,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let beneficiary_signed = list.has(self.extra_signatories, d.beneficiary)
    let refund_signed = list.has(self.extra_signatories, d.refund_to)
    let before_deadline = interval.is_entirely_before(self.validity_range, d.deadline)
    let after_deadline = interval.is_entirely_after(self.validity_range, d.deadline)

    let release_path = beneficiary_signed && before_deadline
    let refund_path = after_deadline && refund_signed

    release_path || refund_path
  }
}

use aiken/collection/list
