pub type ListingDatum {
  seller: ByteArray,
  price: Int,
  policy_id: ByteArray,
  asset_name: ByteArray,
}

fn seller_receives_enough(outputs: List<Output>, seller: ByteArray, price: Int) -> Bool {
  let seller_outputs =
    list.filter(outputs, fn(o) {
      when o.address.payment_credential is {
        cardano/address.VerificationKey(pkh) -> pkh == seller
        _ -> False
      }
    })
  let total_received =
    list.foldl(seller_outputs, 0, fn(o, acc) { acc + assets.lovelace_of(o.value) })
  total_received >= price
}

