    seller_receives_enough(self.outputs, d.seller, d.price)
  }
}

use aiken/collection/list
use aiken/interval
use cardano/assets
use cardano/transaction.{
  InlineDatum, Input, Output, OutputReference, Transaction,
}

pub type SubDatum {
  subscriber: ByteArray,
  expiry: Int,
  fee_per_period: Int,
}

pub type SubRedeemer {
  Renew { new_expiry: Int }
  Cancel
}

fn find_own_input(inputs: List<Input>, utxo: OutputReference) -> Option<Input> {
  list.find(inputs, fn(i) { i.output_reference == utxo })
}

fn find_continuing_output(outputs: List<Output>, own_address: cardano/address.Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == own_address })
}

validator subscription {
  spend(
    datum: Option<SubDatum>,
    redeemer: SubRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      Renew { new_expiry } -> {
        // Subscriber must sign
        let signed = list.has(self.extra_signatories, d.subscriber)

        // new_expiry must be strictly greater than current expiry
        let expiry_advances = new_expiry > d.expiry

        // Find own input to determine script address
        expect Some(own_input) = find_own_input(self.inputs, utxo)
        let own_address = own_input.output.address

        // Find continuing output at own address
        expect Some(cont_out) = find_continuing_output(self.outputs, own_address)

        // Continuing output datum must have updated expiry and same subscriber/fee
        let valid_datum =
          when cont_out.datum is {
            InlineDatum(raw) -> {
              expect cont: SubDatum = raw
              cont.subscriber == d.subscriber && cont.expiry == new_expiry && cont.fee_per_period == d.fee_per_period
            }
            _ -> False
          }

        // Continuing output must contain at least fee_per_period more lovelace
        let input_lovelace = assets.lovelace_of(own_input.output.value)
        let cont_lovelace = assets.lovelace_of(cont_out.value)
        let fee_paid = cont_lovelace >= input_lovelace + d.fee_per_period

        signed && expiry_advances && valid_datum && fee_paid
      }

      Cancel -> {
        // Allow cancel only after expiry: tx must be entirely after expiry
        let expired = interval.is_entirely_after(self.validity_range, d.expiry)

        // Subscriber must sign to cancel
        let signed = list.has(self.extra_signatories, d.subscriber)

        expired && signed
      }
    }
  }
}

