use aiken/collection/list

use cardano/transaction.{InlineDatum, DatumHash, NoDatum, Output, Input, Transaction, OutputReference}
use cardano/address.{Address}
use aiken/collection/list
use cardano/assets

pub type EscrowDatum {
  seller: ByteArray,
  buyer: ByteArray,
  amount: Int,
  deadline: Int,
}

pub type EscrowRedeemer {
  Complete
  Refund
  Dispute
}

validator safe_escrow {
  spend(
    datum: Option<EscrowDatum>,
    redeemer: EscrowRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let inputs = self.inputs
    let own_input =
      list.find(inputs, fn(i) { i.output_reference == utxo })

    expect Some(own_in) = own_input

    let own_output = own_in.output

    when own_output.datum is {
      InlineDatum(raw) -> {
        expect typed: EscrowDatum = raw

        when redeemer is {
          Complete -> {
            let seller_signed =
              list.has(self.extra_signatories, typed.seller)
            let buyer_signed =
              list.has(self.extra_signatories, typed.buyer)
            let seller_receives =
              list.any(
                self.outputs,
                fn(o) {
                  when o.address.payment_credential is {
                    cardano/address.VerificationKey(pkh) ->
                      pkh == typed.seller && assets.lovelace_of(o.value) >= typed.amount
                    _ -> False
                  }
                },
              )
            (seller_signed || buyer_signed) && seller_receives
          }

          Refund -> {
            let buyer_signed =
              list.has(self.extra_signatories, typed.buyer)
            let seller_signed =
              list.has(self.extra_signatories, typed.seller)
            let buyer_receives =
              list.any(
                self.outputs,
                fn(o) {
                  when o.address.payment_credential is {
                    cardano/address.VerificationKey(pkh) ->
                      pkh == typed.buyer && assets.lovelace_of(o.value) >= typed.amount
                    _ -> False
                  }
                },
              )
            (buyer_signed || seller_signed) && buyer_receives
          }

          Dispute -> {
            let seller_signed =
              list.has(self.extra_signatories, typed.seller)
            let buyer_signed =
              list.has(self.extra_signatories, typed.buyer)
            seller_signed && buyer_signed
          }
        }
      }

      DatumHash(_) -> fail @"DatumHash not supported: only inline datums are accepted"

      NoDatum -> fail @"NoDatum not supported: only inline datums are accepted"
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/assets
use cardano/transaction.{
  InlineDatum, Input, Output, OutputReference, Transaction,
}

pub type BridgeDatum {
  amount: Int,
  recipient: ByteArray,
  nonce: ByteArray,
}

pub type NonceDatum {
  used_nonces: List<ByteArray>,
}

fn find_nonce_datum(reference_inputs: List<Input>) -> Option<NonceDatum> {
  let result =
    list.find(
      reference_inputs,
      fn(input) {
        when input.output.datum is {
          InlineDatum(raw) -> {
            expect _nd: NonceDatum = raw
            True
          }
          _ -> False
        }
      },
    )
  when result is {
    Some(input) ->
      when input.output.datum is {
        InlineDatum(raw) -> {
          expect nd: NonceDatum = raw
          Some(nd)
        }
        _ -> None
      }
    None -> None
  }
}

fn nonce_not_used(nonce_datum: NonceDatum, nonce: ByteArray) -> Bool {
  !list.has(nonce_datum.used_nonces, nonce)
}

fn output_to_recipient(
  outputs: List<Output>,
  recipient: ByteArray,
  amount: Int,
) -> Bool {
  list.any(
    outputs,
    fn(output) {
      let paid_enough = assets.lovelace_of(output.value) >= amount
      when output.address.payment_credential is {
        cardano/address.VerificationKey(pkh) ->
          pkh == recipient && paid_enough
        _ -> False
      }
    },
  )
}

validator bridge_release {
  spend(
    datum: Option<BridgeDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let nonce_datum_opt = find_nonce_datum(self.reference_inputs)
    expect Some(nonce_datum) = nonce_datum_opt

    let nonce_ok = nonce_not_used(nonce_datum, d.nonce)

    let recipient_paid =
      output_to_recipient(self.outputs, d.recipient, d.amount)

    nonce_ok && recipient_paid
  }
}

use cardano/assets
use cardano/transaction.{InlineDatum, Output, OutputReference, Transaction}
use aiken/collection/list

pub type TxDatum {
  recipient: ByteArray,
  fee_address: Option<ByteArray>,
  amount: Int,
}

fn address_payment_key(output: Output) -> ByteArray {
  when output.address.payment_credential is {
    cardano/address.VerificationKey(pkh) -> pkh
    _ -> #""
  }
}

validator optional_fee {
  spend(
    datum: Option<TxDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let recipient_signed = list.has(self.extra_signatories, d.recipient)

    let fee_ok =
      when d.fee_address is {
        None -> True
        Some(fee_pkh) -> {
          let fee_outputs =
            list.filter(
              self.outputs,
              fn(o) {
                when o.address.payment_credential is {
                  VerificationKey(pkh) -> pkh == fee_pkh
                  _ -> False
                }
              },
            )
          let total_fee =
            list.foldl(
              fee_outputs,
              0,
              fn(o, acc) { acc + assets.lovelace_of(o.value) },
            )
          total_fee > 0
        }
      }

    recipient_signed && fee_ok
  }
}

use aiken/collection/list
use aiken/interval
use cardano/address.{Address}
use cardano/assets
use cardano/transaction.{
  InlineDatum, Input, Output, OutputReference, Transaction,
}

pub type RecurringDatum {
  payer: ByteArray,
  payee: ByteArray,
  amount: Int,
  period_secs: Int,
  last_paid: Int,
}

pub type RecurringRedeemer {
  MakePayment
  Cancel
}

fn find_output_by_address(outputs: List<Output>, addr: Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == addr })
}

validator recurring_payment {
  spend(
    datum: Option<RecurringDatum>,
    redeemer: RecurringRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      MakePayment -> {
        let deadline = d.last_paid + d.period_secs
        let period_elapsed =
          interval.is_entirely_after(self.validity_range, deadline)

        let payee_receives_enough =
          list.any(
            self.outputs,
            fn(o) {
              when o.datum is {
                InlineDatum(_) ->
                  assets.lovelace_of(o.value) >= d.amount && list.any(
                    self.extra_signatories,
                    fn(_) { True },
                  )
                _ -> assets.lovelace_of(o.value) >= d.amount
              }
            },
          )

        let payee_paid =
          list.any(
            self.outputs,
            fn(o) {
              when o.address.payment_credential is {
                cardano/address.VerificationKey(pkh) ->
                  pkh == d.payee && assets.lovelace_of(o.value) >= d.amount
                _ -> False
              }
            },
          )

        let _ = payee_receives_enough

        let script_continues =
          list.any(
            self.inputs,
            fn(i) { i.output_reference == utxo },
          )

        let _ = script_continues

        let payer_signed = list.has(self.extra_signatories, d.payer)

        period_elapsed && payee_paid && payer_signed
      }

      Cancel -> list.has(self.extra_signatories, d.payer)
    }
  }
}
